CREATE OR REPLACE FUNCTION OFSERM.INVESTMENT_FIXED_ASSETS_DATA_POPULATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_INVESTMENT_EXPOSURES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_FIXED_ASSET_TYPE_SKEY,N_GAAP_SKEY,N_RUN_SKEY,N_CURR_12M_ECL,N_EXPOSURE_AMOUNT,N_GENERAL_PROVISION_AMT,N_LOSS_ALLOWANCE_LIFE_ECL,V_DATA_SOURCE,N_ENTITY_SKEY,N_SHAREHOLDING_PERCENT,F_CREDIT_IMPAIRMENT_FLAG,F_EXP_TREATED_AS_HIGH_RISK,F_FINANCIAL_ASSET_IFRS9_FLAG,N_ADJUSTED_LGD_PERCENT,N_DVA_AMOUNT,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,V_APPROACH_TYPE,N_CAP_APPROACH_TYPE_SKEY,N_EXCHANGE_RATE,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_LOAD_RUN_ID,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_FIXED_ASSETS_TYPE.N_FIXED_ASSET_TYPE_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_RUN.N_RUN_SKEY),CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,STG_FIXED_ASSETS_DETAILS.N_BOOK_VALUE * FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,FSI_ACCT_MODELING_INFO.N_STAGE_I_ALLOWANCES + FSI_ACCT_MODELING_INFO.N_STAGE_II_ALLOWANCES,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,'STG_FIXED_ASSETS_DETAILS',to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FCT_ENTITY_INFO.N_SHAREHOLDING_PERCENT),FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_EXP_TREATED_AS_HIGH_RISK,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,to_char(FSI_ACCT_MODELING_INFO.N_ADJUSTED_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_DVA_AMOUNT),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(STG_FIXED_ASSETS_DETAILS.N_LOAD_RUN_ID),STG_FIXED_ASSETS_DETAILS.V_ISO_CURRENCY_CD FROM STG_FIXED_ASSETS_DETAILS INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = STG_FIXED_ASSETS_DETAILS.FIC_MIS_DATE AND DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.V_ENTITY_CODE = STG_FIXED_ASSETS_DETAILS.V_LV_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY INNER JOIN DIM_EXPOSURE ON DIM_EXPOSURE.V_EXPOSURE_ID = 'FIXAS_' || STG_FIXED_ASSETS_DETAILS.V_FIXED_ASSET_CD AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE INNER JOIN DIM_PARTY ON DIM_PARTY.V_PARTY_ID = COALESCE(STG_FIXED_ASSETS_DETAILS.V_LV_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE LEFT JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = STG_FIXED_ASSETS_DETAILS.V_LV_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT JOIN DIM_COUNTRY ON DIM_COUNTRY.V_COUNTRY_ID = COALESCE(STG_FIXED_ASSETS_DETAILS.V_OREO_COUNTRY_ID, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT JOIN DIM_LOB ON DIM_LOB.V_LOB_CODE = STG_FIXED_ASSETS_DETAILS.V_LOB_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.D_RECORD_START_DATE AND DIM_LOB.D_RECORD_END_DATE LEFT JOIN DIM_GEOGRAPHY ON DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE = STG_FIXED_ASSETS_DETAILS.V_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT JOIN DIM_GAAP ON DIM_GAAP.V_GAAP_CODE = STG_FIXED_ASSETS_DETAILS.V_GAAP_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT JOIN DIM_CURRENCY ON DIM_CURRENCY.V_ISO_CURRENCY_CD = STG_FIXED_ASSETS_DETAILS.V_ISO_CURRENCY_CD AND to_date('20260331','YYYYMMDD') BETWEEN DIM_CURRENCY.D_RECORD_START_DATE AND DIM_CURRENCY.D_RECORD_END_DATE LEFT JOIN DIM_FIXED_ASSETS ON DIM_FIXED_ASSETS.V_FIXED_ASSET_CD = STG_FIXED_ASSETS_DETAILS.V_FIXED_ASSET_CD AND to_date('20260331','YYYYMMDD') BETWEEN DIM_FIXED_ASSETS.D_RECORD_START_DATE AND DIM_FIXED_ASSETS.D_RECORD_END_DATE LEFT JOIN DIM_FIXED_ASSETS_TYPE ON DIM_FIXED_ASSETS_TYPE.V_FIXED_ASSET_TYPE = DIM_FIXED_ASSETS.V_FIXED_ASSET_TYPE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_FIXED_ASSETS_TYPE.D_RECORD_START_DATE AND DIM_FIXED_ASSETS_TYPE.D_RECORD_END_DATE LEFT JOIN RUN_EXE_PARAMETERS ON RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE LEFT JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_FIXED_ASSETS_DETAILS.V_ISO_CURRENCY_CD LEFT JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_EXP' LEFT JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT JOIN FSI_CAP_ACCOUNT_PORTFOLIO_MAP ON FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_RUN_SKEY = '870' AND FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_CAP_APPROACH_TYPE_SKEY AND DIM_EXPOSURE.V_EXPOSURE_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_ACCOUNT_NUMBER AND DIM_GAAP.V_GAAP_CODE = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.V_GAAP_CODE AND DIM_DATES.D_CALENDAR_DATE = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.FIC_MIS_DATE AND STG_FIXED_ASSETS_DETAILS.N_LOAD_RUN_ID = FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_LOAD_RUN_ID WHERE 1=1 AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = STG_FIXED_ASSETS_DETAILS.V_FIXED_ASSET_CD AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = STG_FIXED_ASSETS_DETAILS.FIC_MIS_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = STG_FIXED_ASSETS_DETAILS.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_FIXED_ASSETS_DETAILS.N_LOAD_RUN_ID ) AND 1=CASE WHEN (FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG ='N') OR (FSI_BASEL_EXEC_APPR_DETAILS.F_PORTFOLIO_BASED_FLAG ='Y' AND FSI_CAP_ACCOUNT_PORTFOLIO_MAP.N_PORTFOLIO_SKEY IS NOT NULL) THEN 1 ELSE 2 END LOG ERRORS INTO FSI_CAP_INVESTMENT_EXPOSURES$ ('1776768420645_16095600_20260331_1_Job_1588083070281') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
